var f = this, id = f.get_id(), g1 = f.getItem('hrttctluong')._controlBehavior, g2 = f.getItem('hrttctluongbh')._controlBehavior;
var g3 = f.getItem('hrttctpc')._controlBehavior, g4 = f.getItem('hrttdkluong')._controlBehavior, g5 = f.getItem('hrttctluongnet')._controlBehavior;
var v = this._language == 'v', e1 = (v ? 'Mã phụ cấp và hiệu lực từ ngày đã có trong phần thông tin chi tiết, không thể lưu được.' : 'Invalid allowance and effective date from, it already exists.');
var e0 = (v ? 'Trường <span class="Highlight">Đến ngày</span> phải lớn hơn hoặc bằng <span class="Highlight">Hiệu lực từ ngày</span>.' : '<span class="Highlight">Effective Date to</span> must not be before the <span class="Highlight">Effective Date From</span>.');
var d1 = g3._getColumnOrder('ngay_hl_tu'), d2 = g3._getColumnOrder('ngay_hl_den');

if (f._checked) {
  if (g1._rowCount >= 2) check$EmployeeSalaryInformation$DataGrid(f, g1, 'hrttctluong', 'ngay_hl');
  for (var row = 1; row <= g3._rowCount; row ++) {
    if (g3._getItemValue(row, d1) > g3._getItemValue(row, d2) && g3._getItemValue(row, d2) != null) {
      g3._errorObject = g3._getItem(row, d2);
      $func.hideWait(id);
      f._checked = false;
      $message.show(e0, String.format('$find(\'{0}\').focus(\'hrttctpc\');$find(\'{1}\')._errorObject.focus()', id, g3.get_id()));
      break;
    }
  }
  if (g2._rowCount >= 2) check$EmployeeSalaryInformation$DataGrid(f, g2, 'hrttctluongbh', 'ngay_hl');
  if (g4._rowCount >= 2) check$EmployeeSalaryInformation$DataGrid(f, g4, 'hrttdkluong', 'ngay_hl');
  if (g5._rowCount >= 2) check$EmployeeSalaryInformation$DataGrid(f, g5, 'hrttctluongnet', 'ngay_hl');
}

if (f._checked) {
  var a = query$Select(g3, 'count$1 $groupBy ma_pc, ngay_hl_tu');
  for (var i = 0; i < a.length; i++) {
    if (a[i][2] > 1) {
      f._checked = false;
      $func.hideWait(id);
      $message.show(e1, String.format('$find(\'{0}\').focus(\'hrttctpc\');$find(\'{1}\')._focusWhenTabChanged()', id, g3.get_id()));
      break;
    }
  }
}

