function load$EmployeeSalaryInformation(f) {
  var l = f._language == 'v' ? '' : '2';
  f.setReadOnlyFields('ma_nv, bo_phan, vi_tri, bac_quan_ly, ho_ten, ten_bp' + l + ', ten_vtr' + l + ', ngay_vao');

  f.getItem('tk_nh').maxLength = parseInt(f._externalLength);
  f.getItem('tk_nh').focus();

  f.add_commandEvent(on$EmployeeSalaryInformation$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  &ListCreate;
  &PostCreate;
}
function close$EmployeeSalaryInformation(f) {
  try {f.remove_commandEvent(on$EmployeeSalaryInformation$ExecuteCommand);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['loai_luong', 'hrttctluong', 'hrttctpc', 'hrttctluongbh', 'hrttdkluong'&ListTabChange;&PostTabChange;, 'hrttctluongnet']);
  &PostTabFocus;
}
function on$EmployeeSalaryInformation$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender;
  var g = f.getItem('hrttctluong')._controlBehavior, y = f.getItem('hrttctpc')._controlBehavior, z = f.getItem('hrttctluongbh')._controlBehavior;
  var p = f.getItem('hrttdkluong')._controlBehavior, n = f.getItem('hrttctluongnet')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      y.setSequenceNumber('line_nbr');
      y.setContinuance('stt_rec0');
      z.setSequenceNumber('line_nbr');
      z.setContinuance('stt_rec0');
      p.setSequenceNumber('line_nbr');
      p.setContinuance('stt_rec0');
      n.setSequenceNumber('line_nbr');
      n.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    &ListResponseTicket;
    default:
      break;
  }
}
function check$EmployeeSalaryInformation$DataGrid(f, g, d, s1) {
  var id = f.get_id(), gID = g.get_id(), v = f._language == 'v';
  var e1 = (v ? 'Trường <span class="Highlight">Hiệu lực từ ngày</span> chưa nhập hoặc giá trị không hợp lệ.' : 'Field <span class="Highlight">Effective from</span> must not be blank or has invalid value.');
  var t1 = g._getColumnOrder(s1);
  if (f._checked) {
    for (var i = 1; i < g._rowCount; i++) {
      if (!f._checked) break;
      for (var j = i + 1; j <= g._rowCount; j++) {
        var d1 = g._getItemValue(i, t1).valueOf(), d2 = g._getItemValue(j, t1).valueOf();
        if (d1 == d2) {
          g._errorWarningObject = g._getItem(j, t1);
          $func.hideWait(id);
          $message.show(e1, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorWarningObject.focus()', id, d, gID));
          f._checked = false;
          break;
        }
      }
    }
  }
}

